package evaluation

import "sync/atomic"

// MetricsTracker records evaluation throughput counters in a thread-safe manner.
type MetricsTracker struct {
	total  atomic.Int64
	match  atomic.Int64
	errors atomic.Int64
}

// RecordEvaluation increments the total evaluations counter.
func (m *MetricsTracker) RecordEvaluation() {
	m.total.Add(1)
}

// RecordMatch increments the match counter.
func (m *MetricsTracker) RecordMatch() {
	m.match.Add(1)
}

// RecordError increments the error counter.
func (m *MetricsTracker) RecordError() {
	m.errors.Add(1)
}

// Total returns the number of evaluations processed.
func (m *MetricsTracker) Total() int64 {
	return m.total.Load()
}

// Matches returns the number of evaluations that resulted in a successful match.
func (m *MetricsTracker) Matches() int64 {
	return m.match.Load()
}

// Errors returns the number of evaluations that failed with errors.
func (m *MetricsTracker) Errors() int64 {
	return m.errors.Load()
}

